import{_ as a,c as l,o as s,a1 as t}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"相容性: Claude Code 技能 | opencode-agent-skills","description":"學習 OpenCode Agent Skills 如何相容 Claude Code 技能和插件系統。掌握工具對應機制、技能發現優先順序，復用 Claude 技能生態。","frontmatter":{"title":"相容性: Claude Code 技能 | opencode-agent-skills","sidebarTitle":"復用 Claude 技能","subtitle":"Claude Code 技能相容性","description":"學習 OpenCode Agent Skills 如何相容 Claude Code 技能和插件系統。掌握工具對應機制、技能發現優先順序，復用 Claude 技能生態。","tags":["相容性","Claude Code","技能復用"],"prerequisite":["start-what-is-opencode-agent-skills","platforms-skill-discovery-mechanism"],"order":1},"headers":[],"relativePath":"zh-tw/joshuadavidthomas/opencode-agent-skills/advanced/claude-code-compatibility/index.md","filePath":"zh-tw/joshuadavidthomas/opencode-agent-skills/advanced/claude-code-compatibility/index.md"}'),d={name:"zh-tw/joshuadavidthomas/opencode-agent-skills/advanced/claude-code-compatibility/index.md"};function o(i,e,n,r,c,p){return s(),l("div",null,[...e[0]||(e[0]=[t(`<h1 id="claude-code-技能相容性" tabindex="-1">Claude Code 技能相容性 <a class="header-anchor" href="#claude-code-技能相容性" aria-label="Permalink to &quot;Claude Code 技能相容性&quot;">​</a></h1><h2 id="學完你能做什麼" tabindex="-1">學完你能做什麼 <a class="header-anchor" href="#學完你能做什麼" aria-label="Permalink to &quot;學完你能做什麼&quot;">​</a></h2><ul><li>理解插件如何自動相容 Claude Code 技能格式</li><li>掌握工具對應機制，讓 Claude 技能在 OpenCode 中正確運作</li><li>了解技能發現的完整優先順序規則</li><li>復用 Claude 插件市場中的現有技能，無需重新編寫</li></ul><h2 id="你現在的困境" tabindex="-1">你現在的困境 <a class="header-anchor" href="#你現在的困境" aria-label="Permalink to &quot;你現在的困境&quot;">​</a></h2><p>你已經有一些 Claude Code 的技能，或者想用 Claude 插件市場上的技能，但這些技能都是為 Claude Code 編寫的。直接在 OpenCode 中使用會遇到問題：</p><ul><li>Claude 技能中的工具呼叫（如 <code>TodoWrite</code>、<code>Task</code>）在 OpenCode 中不存在</li><li>不清楚如何讓 OpenCode 找到已安裝的 Claude 插件技能</li><li>擔心技能格式不相容，需要重寫所有內容</li></ul><h2 id="核心思路" tabindex="-1">核心思路 <a class="header-anchor" href="#核心思路" aria-label="Permalink to &quot;核心思路&quot;">​</a></h2><p>OpenCode Agent Skills 插件透過<strong>三層相容機制</strong>，讓你無需修改即可使用 Claude Code 技能：</p><ol><li><strong>自動發現</strong> - 從 Claude Code 的標準目錄（<code>.claude/skills/</code>、<code>~/.claude/plugins/</code>）掃描技能</li><li><strong>工具對應</strong> - 載入技能時自動注入工具對應指南，將 Claude 工具名轉為 OpenCode 工具名</li><li><strong>格式支援</strong> - 同時支援 Claude 插件的 v1 和 v2 兩種安裝格式</li></ol><div class="info custom-block"><p class="custom-block-title">關鍵概念</p><p><strong>Claude Code 技能格式</strong> - Anthropic 定義的技能規範，使用 <code>SKILL.md</code> 檔案描述技能，包含 YAML frontmatter（中繼資料）和 Markdown 內容（指令）。</p></div><h3 id="工具對應原理" tabindex="-1">工具對應原理 <a class="header-anchor" href="#工具對應原理" aria-label="Permalink to &quot;工具對應原理&quot;">​</a></h3><p>當插件檢測到載入的是 Claude Code 編寫的技能時，會自動注入工具對應指南：</p><table tabindex="0"><thead><tr><th>Claude Code 工具</th><th>OpenCode 工具</th><th>對應規則</th></tr></thead><tbody><tr><td><code>TodoWrite/TodoRead</code></td><td><code>todowrite/todoread</code></td><td>小寫</td></tr><tr><td><code>Task</code> (子代理)</td><td><code>task</code> (帶 subagent_type 參數)</td><td>改用參數</td></tr><tr><td><code>Skill</code></td><td><code>use_skill</code></td><td>替換工具名</td></tr><tr><td><code>Read/Write/Edit/Bash/Glob/Grep/WebFetch</code></td><td><code>read/write/edit/bash/glob/grep/webfetch</code></td><td>小寫</td></tr></tbody></table><p><strong>對應方式</strong>：插件在載入技能時，將對應指南作為 XML 注入到會話上下文中，AI 會自動按照對應呼叫正確的工具。</p><div class="tip custom-block"><p class="custom-block-title">為什麼需要對應？</p><p>Claude Code 和 OpenCode 的工具命名風格不同。Claude 使用 PascalCase（如 <code>TodoWrite</code>），OpenCode 使用小寫（如 <code>todowrite</code>）。工具對應讓 AI 知道如何轉換呼叫。</p></div><h3 id="技能發現優先順序" tabindex="-1">技能發現優先順序 <a class="header-anchor" href="#技能發現優先順序" aria-label="Permalink to &quot;技能發現優先順序&quot;">​</a></h3><p>插件按照以下順序發現技能，<strong>第一個匹配的技能生效</strong>（同名技能不會重複）：</p><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">graph TD</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A[技能發現流程] --&gt; B[項目級 OpenCode]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B --&gt; |.opencode/skills/| C[1. project]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt; D[項目級 Claude Code]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    D --&gt; |.claude/skills/| E[2. claude-project]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    E --&gt; F[用戶級 OpenCode]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    F --&gt; |~/.config/opencode/skills/| G[3. user]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    G --&gt; H[用戶級 Claude Code]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    H --&gt; |~/.claude/skills/| I[4. claude-user]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    I --&gt; J[Claude 插件快取]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    J --&gt; |~/.claude/plugins/cache/| K[5. claude-plugins]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    K --&gt; L[Claude 插件市場]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    L --&gt; |~/.claude/plugins/marketplaces/| M[6. claude-plugins]</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style C fill:#e1f5e1</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style E fill:#fff4e1</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style G fill:#e1f5e1</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style I fill:#fff4e1</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style K fill:#fff4e1</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style M fill:#fff4e1</span></span></code></pre></div><p><strong>優先順序規則</strong>：</p><ul><li>項目級技能覆蓋用戶級技能（方便項目定制）</li><li>OpenCode 技能優先於 Claude 技能（避免混淆）</li><li>同名技能只保留首次發現的版本</li></ul><details class="details custom-block"><summary>範例：同名技能覆蓋</summary><p>假設你在兩個位置都有名為 <code>git-helper</code> 的技能：</p><ul><li><code>.claude/skills/git-helper/SKILL.md</code> （Claude 版本）</li><li><code>.opencode/skills/git-helper/SKILL.md</code> （OpenCode 版本）</li></ul><p><strong>結果</strong>：OpenCode 版本生效（優先順序更高）</p></details><h2 id="🎒-開始前的準備" tabindex="-1">🎒 開始前的準備 <a class="header-anchor" href="#🎒-開始前的準備" aria-label="Permalink to &quot;🎒 開始前的準備&quot;">​</a></h2><ul><li>已安裝並設定 OpenCode Agent Skills 插件</li><li>了解基礎技能概念（推薦先閱讀<a href="./../../start/what-is-opencode-agent-skills/">什麼是 OpenCode Agent Skills？</a>）</li><li>（可選）有 Claude Code 的已安裝插件或技能</li></ul><h2 id="跟我做" tabindex="-1">跟我做 <a class="header-anchor" href="#跟我做" aria-label="Permalink to &quot;跟我做&quot;">​</a></h2><h3 id="第-1-步-檢查-claude-技能是否被發現" tabindex="-1">第 1 步：檢查 Claude 技能是否被發現 <a class="header-anchor" href="#第-1-步-檢查-claude-技能是否被發現" aria-label="Permalink to &quot;第 1 步：檢查 Claude 技能是否被發現&quot;">​</a></h3><p><strong>為什麼</strong> 確認插件能正確掃描到你的 Claude Code 技能目錄。</p><p>在 OpenCode 中呼叫工具：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>get_available_skills()</span></span></code></pre></div><p><strong>你應該看到</strong>：返回的技能列表中包含來自 <code>.claude/skills/</code>、<code>~/.claude/skills/</code>、<code>~/.claude/plugins/</code> 的技能，每個技能的 <code>source</code> 欄位顯示來源（如 <code>claude-project</code>、<code>claude-user</code>、<code>claude-plugins</code>）。</p><p><strong>檢查點 ✅</strong>：確認列表中包含預期的 Claude 技能。</p><h3 id="第-2-步-載入-claude-技能" tabindex="-1">第 2 步：載入 Claude 技能 <a class="header-anchor" href="#第-2-步-載入-claude-技能" aria-label="Permalink to &quot;第 2 步：載入 Claude 技能&quot;">​</a></h3><p><strong>為什麼</strong> 驗證工具對應機制是否正常運作。</p><p>呼叫工具載入一個 Claude 技能：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>use_skill(skill=&quot;你的技能名稱&quot;)</span></span></code></pre></div><p><strong>你應該看到</strong>：返回成功訊息，如 <code>Skill &quot;xxx&quot; loaded.</code>。</p><p><strong>檢查點 ✅</strong>：AI 現在可以使用該技能的指令。</p><h3 id="第-3-步-驗證工具對應生效" tabindex="-1">第 3 步：驗證工具對應生效 <a class="header-anchor" href="#第-3-步-驗證工具對應生效" aria-label="Permalink to &quot;第 3 步：驗證工具對應生效&quot;">​</a></h3><p><strong>為什麼</strong> 確認 AI 能正確呼叫 OpenCode 的工具而非 Claude 的工具。</p><p>向 AI 提出一個需要該技能工具的任務，例如：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>請用技能中的 todo 功能幫我建立任務列表。</span></span></code></pre></div><p><strong>你應該看到</strong>：AI 正確呼叫 OpenCode 的 <code>todowrite</code> 工具，而不是 Claude 的 <code>TodoWrite</code> 工具。</p><div class="tip custom-block"><p class="custom-block-title">如何驗證對應生效？</p><p>查看 AI 的工具呼叫日誌（如果啟用了除錯模式），你會看到它呼叫的是 <code>todowrite</code> 而非 <code>TodoWrite</code>。</p></div><p><strong>檢查點 ✅</strong>：工具呼叫成功，任務完成。</p><h2 id="踩坑提醒" tabindex="-1">踩坑提醒 <a class="header-anchor" href="#踩坑提醒" aria-label="Permalink to &quot;踩坑提醒&quot;">​</a></h2><h3 id="_1-插件格式不匹配" tabindex="-1">1. 插件格式不匹配 <a class="header-anchor" href="#_1-插件格式不匹配" aria-label="Permalink to &quot;1. 插件格式不匹配&quot;">​</a></h3><p><strong>問題</strong>：舊版 Claude 插件使用 v1 格式，新版使用 v2 格式，導致某些技能無法被發現。</p><p><strong>原因</strong>：v1 和 v2 的 <code>installed_plugins.json</code> 結構不同。</p><p><strong>解決</strong>：插件同時支援兩種格式，無需手動轉換。如果仍無法發現技能，檢查 <code>~/.claude/plugins/installed_plugins.json</code> 是否存在且格式正確。</p><h3 id="_2-工具對應未生效" tabindex="-1">2. 工具對應未生效 <a class="header-anchor" href="#_2-工具對應未生效" aria-label="Permalink to &quot;2. 工具對應未生效&quot;">​</a></h3><p><strong>問題</strong>：AI 仍呼叫 Claude 工具名，導致報錯。</p><p><strong>原因</strong>：技能內容可能繞過了工具對應指南，或者使用了硬編碼的工具呼叫。</p><p><strong>解決</strong>：</p><ul><li>確認技能是載入後使用，而非直接呼叫工具</li><li>如果技能中有程式碼範例，手動將工具名改為 OpenCode 格式</li></ul><h3 id="_3-技能命名衝突" tabindex="-1">3. 技能命名衝突 <a class="header-anchor" href="#_3-技能命名衝突" aria-label="Permalink to &quot;3. 技能命名衝突&quot;">​</a></h3><p><strong>問題</strong>：同名技能在不同位置，載入的是錯誤的版本。</p><p><strong>原因</strong>：技能發現優先順序導致的覆蓋。</p><p><strong>解決</strong>：</p><ul><li>檢查技能的 <code>source</code> 欄位，確認來源</li><li>使用命名空間格式明確指定來源：<code>use_skill(skill=&quot;user:skill-name&quot;)</code> 或 <code>use_skill(skill=&quot;claude-plugins:skill-name&quot;)</code></li></ul><details class="details custom-block"><summary>命名空間語法</summary><p>插件支援 <code>namespace:skill-name</code> 格式：</p><ul><li><code>project:skill-name</code> - 專案級 OpenCode 技能</li><li><code>claude-project:skill-name</code> - 專案級 Claude 技能</li><li><code>user:skill-name</code> - 用戶級 OpenCode 技能</li><li><code>claude-user:skill-name</code> - 用戶級 Claude 技能</li><li><code>claude-plugins:skill-name</code> - Claude 插件市場技能</li></ul></details><h2 id="本課小結" tabindex="-1">本課小結 <a class="header-anchor" href="#本課小結" aria-label="Permalink to &quot;本課小結&quot;">​</a></h2><p>OpenCode Agent Skills 插件透過三層相容機制，讓你無縫復用 Claude Code 技能：</p><ul><li><strong>自動發現</strong> - 從 6 個位置掃描技能，覆蓋專案級、用戶級、插件級</li><li><strong>工具對應</strong> - 自動將 Claude 工具名轉換為 OpenCode 工具名</li><li><strong>格式支援</strong> - 同時支援 v1 和 v2 兩種 Claude 插件格式</li></ul><p>無需重寫技能，直接安裝並使用，插件會自動處理相容性問題。</p><h2 id="下一課預告" tabindex="-1">下一課預告 <a class="header-anchor" href="#下一課預告" aria-label="Permalink to &quot;下一課預告&quot;">​</a></h2><blockquote><p>下一課我們學習 <strong><a href="./../superpowers-integration/">Superpowers 工作流程整合</a></strong>。</p><p>你會學到：</p><ul><li>如何啟用 Superpowers 模式</li><li>Superpowers 技能的自動檢測和載入</li><li>嚴格工作流程如何提升開發效率</li></ul></blockquote><hr><h2 id="附錄-原始碼參考" tabindex="-1">附錄：原始碼參考 <a class="header-anchor" href="#附錄-原始碼參考" aria-label="Permalink to &quot;附錄：原始碼參考&quot;">​</a></h2><details><summary><strong>點選展開查看原始碼位置</strong></summary><blockquote><p>更新時間：2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>功能</th><th>檔案路徑</th><th>行號</th></tr></thead><tbody><tr><td>工具對應定義</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/claude.ts#L19-L25" target="_blank" rel="noreferrer"><code>src/claude.ts</code></a></td><td>19-25</td></tr><tr><td>v1/v2 格式型別定義</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/claude.ts#L35-L61" target="_blank" rel="noreferrer"><code>src/claude.ts</code></a></td><td>35-61</td></tr><tr><td>插件安裝路徑提取</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/claude.ts#L68-L77" target="_blank" rel="noreferrer"><code>src/claude.ts</code></a></td><td>68-77</td></tr><tr><td>發現插件技能</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/claude.ts#L82-L105" target="_blank" rel="noreferrer"><code>src/claude.ts</code></a></td><td>82-105</td></tr><tr><td>發現市場技能</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/claude.ts#L115-L180" target="_blank" rel="noreferrer"><code>src/claude.ts</code></a></td><td>115-180</td></tr><tr><td>發現快取技能</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/claude.ts#L193-L253" target="_blank" rel="noreferrer"><code>src/claude.ts</code></a></td><td>193-253</td></tr><tr><td>技能發現優先順序列表</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/skills.ts#L241-L254" target="_blank" rel="noreferrer"><code>src/skills.ts</code></a></td><td>241-254</td></tr><tr><td>同名技能去重邏輯</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/skills.ts#L256-L260" target="_blank" rel="noreferrer"><code>src/skills.ts</code></a></td><td>256-260</td></tr><tr><td>toolTranslation 匯入</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/tools.ts#L15" target="_blank" rel="noreferrer"><code>src/tools.ts</code></a></td><td>15</td></tr><tr><td>工具對應注入</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/tools.ts#L238-L249" target="_blank" rel="noreferrer"><code>src/tools.ts</code></a></td><td>238-249</td></tr></tbody></table><p><strong>關鍵常數</strong>：</p><ul><li><code>toolTranslation</code>：工具對應指南 XML 字串，在載入技能時注入到會話上下文。在 <code>src/claude.ts:19-25</code> 定義，在 <code>src/tools.ts:15</code> 匯入</li></ul><p><strong>關鍵函數</strong>：</p><ul><li><code>getPluginInstallPaths()</code>：從 v1/v2 格式中提取插件安裝路徑</li><li><code>discoverSkillsFromPluginDir()</code>：掃描插件目錄的 skills/ 子目錄</li><li><code>discoverMarketplaceSkills()</code>：從 <code>~/.claude/plugins/marketplaces/</code> 發現技能（優先）</li><li><code>discoverPluginCacheSkills()</code>：從 <code>~/.claude/plugins/cache/</code> 發現技能（作為降級方案）</li><li><code>findFile()</code>：遞迴搜尋指定檔案名（工具函數）</li></ul><p><strong>重要流程</strong>：</p><ol><li>插件初始化時呼叫 <code>discoverAllSkills()</code> → 遍歷 6 個發現路徑</li><li>發現 Claude 插件技能時呼叫 <code>discoverMarketplaceSkills()</code> 或 <code>discoverPluginCacheSkills()</code></li><li>載入技能時，<code>use_skill</code> 工具在 XML 內容中插入 <code>toolTranslation</code>（第 244 行）</li></ol></details>`,68)])])}const g=a(d,[["render",o]]);export{u as __pageData,g as default};
